  border: 2px solid #f5c6cb; /* Soft border */
  padding: 20px;
  border-radius: 8px;
  margin-bottom: 25px;
  text-align: center;
  box-shadow: 0 2px 4px rgba(114, 28, 36, 0.05); /* Very subtle shadow */
}

/* Ensure the sub-text inside the banner also stays dark */
.verdict-banner.verdict-danger .banner-subtext {
  font-size: 0.95rem;
  font-weight: 500;
  margin-top: 8px;
  color: #842029; /* Slightly lighter than the heading, but still dark */
}

.verdict-banner.verdict-safe {
  background-color: #27ae60;
  color: white;
  padding: 20px;
  border-radius: 8px;
}

