appsmith.onReady(() => {
  const model = appsmith.model;
  renderIntegrityAudit(model);
});
appsmith.onModelChange(newModel => {
  renderIntegrityAudit(newModel);
});
function renderIntegrityAudit(model) {
  if (!model || !model.scriptData) return;
  const rawScripts = model.scriptData;
  const rootKey = Object.keys(rawScripts)[0];
  const scripts = rootKey ? rawScripts[rootKey] : {};
  const tbody = document.getElementById('integrity-body');
  if (!tbody) return;
  tbody.innerHTML = "";
  let processedRows = [];
  let compromisedCount = 0;
  let secretCount = 0;
  Object.entries(scripts).forEach(([url, info]) => {
    const fileName = url.split('/').pop();
    const sensitive = info["sensitive PIIs"] || [];
    const pii = info.PIIs || [];
    let severity = "LOW";
    let definition = "No Secrets";
    let riskClass = "badge-safe";
    let sortWeight = 0;
    let violationType = "Aligned";
    if (sensitive.length > 0) {
      severity = "CRITICAL";
      definition = "Credential Leak";
      riskClass = "badge-critical";
      sortWeight = 2;
      violationType = "Section 13 (Confidentiality)";
      compromisedCount++;
      secretCount += sensitive.length;
    } else if (pii.length > 0) {
      severity = "HIGH";
      definition = "PII Exposure";
      riskClass = "badge-high";
      sortWeight = 1;
      violationType = "Section 3 (Identity Protection)";
      compromisedCount++;
    }
    if (severity !== "LOW") {
      processedRows.push({
        fileName,
        findings: [...sensitive, ...pii].join(", "),
        severity,
        definition,
        riskClass,
        sortWeight,
        violationType
      });
    }
  });
  processedRows.sort((a, b) => b.sortWeight - a.sortWeight);
  processedRows.forEach(row => {
    const tr = document.createElement('tr');
    tr.innerHTML = `
            <td><code>${row.fileName}</code></td>
            <td>${row.findings}</td>
            <td>
                <div class="risk-stack">
                    <span class="badge ${row.riskClass}">${row.severity}</span>
                    <span class="badge-sub">${row.definition}</span>
                </div>
            </td>
            <td class="status-violation"><strong>POLICY DRIFT:</strong><br>${row.violationType}</td>
        `;
    tbody.appendChild(tr);
  });
  document.getElementById('compromised-count').textContent = compromisedCount;
  document.getElementById('secret-count').textContent = secretCount;
  const banner = document.getElementById('verdict-banner');
  const h2 = banner.querySelector('h2');
  if (compromisedCount > 0) {
    banner.className = "verdict-banner verdict-danger";
    // Replaced "INTEGRITY BREACH" with "Client-Side Exposure Detected"
    h2.innerHTML = `⚠️ CLIENT-SIDE EXPOSURE DETECTED: ${compromisedCount} ASSETS
                        <div style="font-size:0.9rem; font-weight:normal; margin-top:5px;">
                        Hardcoded secrets and PII markers contradict Secure Code policy claims.
                        </div>`;
  } else {
    banner.className = "verdict-banner verdict-safe";
    h2.textContent = "✅ Neural Assets Secure";
  }
}

